public int makeChocolate(int small, int big, int goal) {
    int bigUsed = goal / 5;
    if (bigUsed > big) {
        bigUsed = big;
    }
    int remaining = goal - bigUsed * 5;
    if (remaining > small || remaining < 0) {
        return -1;
    }
    return remaining;
}

